49	/// A body wrapper that holds a token and returns it when the body is fully consumed or dropped.
50	/// This ensures that for streaming responses, the token is only returned after the entire
51	/// stream has been sent to the client.
52	pub struct TokenGuardBody {
53	    inner: Body,
54	    /// The token bucket to return tokens to. Uses Option so we can take() on drop.
55	    token_bucket: Option<Arc<TokenBucket>>,
56	    /// Number of tokens to return.
57	    tokens: f64,
58	}
