60	impl TokenGuardBody {
61	    /// Create a new TokenGuardBody that will return tokens when dropped.
62	    pub fn new(inner: Body, token_bucket: Arc<TokenBucket>, tokens: f64) -> Self {
63	        Self {
64	            inner,
65	            token_bucket: Some(token_bucket),
66	            tokens,
67	        }
68	    }
69	}
