71	impl Drop for TokenGuardBody {
72	    fn drop(&mut self) {
73	        if let Some(bucket) = self.token_bucket.take() {
74	            debug!(
75	                "TokenGuardBody: stream ended, returning {} tokens to bucket",
76	                self.tokens
77	            );
78	            // Use lock-free sync return - no runtime needed, guaranteed token return
79	            bucket.return_tokens_sync(self.tokens);
80	        }
81	    }
82	}
