112	/// Middleware to validate Bearer token against configured API key
113	/// Only active when router has an API key configured
114	pub async fn auth_middleware(
115	    State(auth_config): State<AuthConfig>,
116	    request: Request<Body>,
117	    next: Next,
118	) -> Result<Response, StatusCode> {
119	    if let Some(expected_key) = &auth_config.api_key {
120	        // Extract Authorization header
121	        let auth_header = request
122	            .headers()
123	            .get(header::AUTHORIZATION)
124	            .and_then(|h| h.to_str().ok());
125	
126	        match auth_header {
127	            Some(header_value) if header_value.starts_with("Bearer ") => {
128	                let token = &header_value[7..]; // Skip "Bearer "
129	                                                // Use constant-time comparison to prevent timing attacks
130	                let token_bytes = token.as_bytes();
131	                let expected_bytes = expected_key.as_bytes();
132	
133	                // Check if lengths match first (this is not constant-time but necessary)
134	                if token_bytes.len() != expected_bytes.len() {
135	                    return Err(StatusCode::UNAUTHORIZED);
136	                }
137	
138	                // Constant-time comparison of the actual values
139	                if token_bytes.ct_eq(expected_bytes).unwrap_u8() != 1 {
140	                    return Err(StatusCode::UNAUTHORIZED);
141	                }
142	            }
143	            _ => return Err(StatusCode::UNAUTHORIZED),
144	        }
145	    }
146	
147	    Ok(next.run(request).await)
148	}
