150	/// Alphanumeric characters for request ID generation (as bytes for O(1) indexing)
151	const REQUEST_ID_CHARS: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
152	
153	/// Generate OpenAI-compatible request ID based on endpoint.
154	fn generate_request_id(path: &str) -> String {
155	    let prefix = if path.contains("/chat/completions") {
156	        "chatcmpl-"
157	    } else if path.contains("/completions") {
158	        "cmpl-"
159	    } else if path.contains("/generate") {
160	        "gnt-"
161	    } else if path.contains("/responses") {
162	        "resp-"
163	    } else {
164	        "req-"
165	    };
166	
167	    // Generate a random string similar to OpenAI's format
168	    // Use byte array indexing (O(1)) instead of chars().nth() (O(n))
169	    let mut rng = rand::rng();
170	    let random_part: String = (0..24)
171	        .map(|_| {
172	            let idx = rng.random_range(0..REQUEST_ID_CHARS.len());
173	            REQUEST_ID_CHARS[idx] as char
174	        })
175	        .collect();
176	
177	    format!("{}{}", prefix, random_part)
178	}
