210	#[derive(Clone)]
211	pub struct RequestIdMiddleware<S> {
212	    inner: S,
213	    headers: Arc<Vec<String>>,
214	}
215	
216	impl<S> Service<Request> for RequestIdMiddleware<S>
217	where
218	    S: Service<Request, Response = Response> + Send + 'static,
219	    S::Future: Send + 'static,
220	{
221	    type Response = S::Response;
222	    type Error = S::Error;
223	    type Future =
224	        Pin<Box<dyn std::future::Future<Output = Result<Self::Response, Self::Error>> + Send>>;
225	
226	    fn poll_ready(&mut self, cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
227	        self.inner.poll_ready(cx)
228	    }
229	
230	    fn call(&mut self, mut req: Request) -> Self::Future {
231	        let headers = self.headers.clone();
232	
233	        // Extract request ID from headers or generate new one
234	        let mut request_id = None;
235	
236	        for header_name in headers.iter() {
237	            if let Some(header_value) = req.headers().get(header_name) {
238	                if let Ok(value) = header_value.to_str() {
239	                    request_id = Some(value.to_string());
240	                    break;
241	                }
242	            }
243	        }
244	
245	        let request_id = request_id.unwrap_or_else(|| generate_request_id(req.uri().path()));
246	
247	        // Insert request ID into request extensions for other middleware/handlers to use
248	        req.extensions_mut().insert(RequestId(request_id.clone()));
249	
250	        // Call the inner service
251	        let future = self.inner.call(req);
252	
253	        Box::pin(async move {
254	            let mut response = future.await?;
255	
256	            // Add request ID to response headers
257	            response.headers_mut().insert(
258	                "x-request-id",
259	                HeaderValue::from_str(&request_id)
260	                    .unwrap_or_else(|_| HeaderValue::from_static("invalid-request-id")),
261	            );
262	
263	            Ok(response)
264	        })
265	    }
266	}
