336	        let error_code = extract_error_code_from_response(response);
337	
338	        // Layer 1: HTTP metrics
339	        Metrics::record_http_response(status_code, error_code);
340	
341	        // Record these in the span for structured logging/observability tools
342	        span.record("status_code", status_code);
343	        // Use microseconds as integer to avoid format! string allocation
344	        span.record("latency", latency.as_micros() as u64);
345	
346	        // Log the response completion
347	        let _enter = span.enter();
348	        if status.is_server_error() {
349	            error!(
350	                target: "smg::response",
351	                "request failed with server error"
352	            );
353	        } else if status.is_client_error() {
354	            warn!(
355	                target: "smg::response",
356	                "request failed with client error"
357	            );
358	        } else {
359	            info!(
360	                target: "smg::response",
361	                "finished processing request"
362	            );
363	        }
364	    }
365	}
