398	/// Queue processor that handles queued requests
399	pub struct QueueProcessor {
400	    token_bucket: Arc<TokenBucket>,
401	    queue_rx: mpsc::Receiver<QueuedRequest>,
402	    queue_timeout: Duration,
403	}
404	
405	impl QueueProcessor {
406	    pub fn new(
407	        token_bucket: Arc<TokenBucket>,
408	        queue_rx: mpsc::Receiver<QueuedRequest>,
409	        queue_timeout: Duration,
410	    ) -> Self {
411	        Self {
412	            token_bucket,
413	            queue_rx,
414	            queue_timeout,
415	        }
416	    }
417	
418	    pub async fn run(mut self) {
419	        debug!("Starting concurrency queue processor");
420	
421	        // Process requests in a single task to reduce overhead
422	        while let Some(queued) = self.queue_rx.recv().await {
423	            // Check timeout immediately
424	            let elapsed = queued.queued_at.elapsed();
425	            if elapsed >= self.queue_timeout {
426	                warn!("Request already timed out in queue");
427	                let _ = queued.permit_tx.send(Err(StatusCode::REQUEST_TIMEOUT));
428	                continue;
429	            }
430	
431	            let remaining_timeout = self.queue_timeout - elapsed;
432	
433	            // Try to acquire token for this request
434	            if self.token_bucket.try_acquire(1.0).await.is_ok() {
435	                // Got token immediately
436	                debug!("Queue: acquired token immediately for queued request");
437	                let _ = queued.permit_tx.send(Ok(()));
438	            } else {
439	                // Need to wait for token
440	                let token_bucket = self.token_bucket.clone();
441	
442	                // Spawn task only when we actually need to wait
443	                tokio::spawn(async move {
444	                    if token_bucket
445	                        .acquire_timeout(1.0, remaining_timeout)
446	                        .await
447	                        .is_ok()
448	                    {
449	                        debug!("Queue: acquired token after waiting");
450	                        let _ = queued.permit_tx.send(Ok(()));
451	                    } else {
452	                        warn!("Queue: request timed out waiting for token");
453	                        let _ = queued.permit_tx.send(Err(StatusCode::REQUEST_TIMEOUT));
454	                    }
455	                });
456	            }
457	        }
458	
459	        warn!("Concurrency queue processor shutting down");
460	    }
461	}
