468	impl ConcurrencyLimiter {
469	    /// Create new concurrency limiter with optional queue
470	    pub fn new(
471	        token_bucket: Option<Arc<TokenBucket>>,
472	        queue_size: usize,
473	        queue_timeout: Duration,
474	    ) -> (Self, Option<QueueProcessor>) {
475	        match (token_bucket, queue_size) {
476	            (None, _) => (Self { queue_tx: None }, None),
477	            (Some(bucket), size) if size > 0 => {
478	                let (queue_tx, queue_rx) = mpsc::channel(size);
479	                let processor = QueueProcessor::new(bucket, queue_rx, queue_timeout);
480	                (
