492	/// Middleware function for concurrency limiting with optional queuing
493	pub async fn concurrency_limit_middleware(
494	    State(app_state): State<Arc<AppState>>,
495	    request: Request<Body>,
496	    next: Next,
497	) -> Response {
498	    // Check mesh global rate limit first if mesh is enabled
499	    // If mesh is not enabled, this check is skipped and local rate limiting is used
500	    if let Some(sync_manager) = &app_state.mesh_sync_manager {
501	        let (is_exceeded, current_count, limit) = sync_manager.check_global_rate_limit();
502	        if is_exceeded {
503	            debug!(
504	                "Global rate limit exceeded: {}/{} req/s",
505	                current_count, limit
506	            );
507	            return (
508	                StatusCode::TOO_MANY_REQUESTS,
509	                Json(json!({
510	                    "error": "Rate limit exceeded",
511	                    "current_count": current_count,
512	                    "limit": limit
513	                })),
514	            )
515	                .into_response();
516	        }
517	    }
518	
519	    let token_bucket = match &app_state.context.rate_limiter {
520	        Some(bucket) => bucket.clone(),
521	        None => {
522	            // Rate limiting disabled, pass through immediately
523	            return next.run(request).await;
524	        }
525	    };
526	
527	    // Static counter for embeddings queue size
528	    static EMBEDDINGS_QUEUE_SIZE: AtomicU64 = AtomicU64::new(0);
529	
530	    // Identify if this is an embeddings request based on path
531	    let is_embeddings = request.uri().path().contains("/v1/embeddings");
532	
533	    // Try to acquire token immediately
534	    if token_bucket.try_acquire(1.0).await.is_ok() {
535	        debug!("Acquired token immediately");
536	        Metrics::record_http_rate_limit(metrics_labels::RATE_LIMIT_ALLOWED);
537	        let response = next.run(request).await;
538	
539	        // Wrap the response body with TokenGuardBody to return token when stream ends
540	        // This ensures that for streaming responses, the token is only returned
541	        // after the entire stream has been sent to the client.
542	        let (parts, body) = response.into_parts();
543	        let guarded_body = TokenGuardBody::new(body, token_bucket, 1.0);
544	        Response::from_parts(parts, Body::new(guarded_body))
545	    } else {
546	        // No tokens available, try to queue if enabled
547	        if let Some(queue_tx) = &app_state.concurrency_queue_tx {
548	            debug!("No tokens available, attempting to queue request");
549	
550	            // Create a channel for the token response
551	            let (permit_tx, permit_rx) = oneshot::channel();
552	
553	            let queued = QueuedRequest {
554	                queued_at: Instant::now(),
555	                permit_tx,
556	            };
557	
558	            // Try to send to queue
559	            match queue_tx.try_send(queued) {
560	                Ok(_) => {
561	                    // On successful enqueue, update embeddings queue counter if applicable
562	                    if is_embeddings {
563	                        EMBEDDINGS_QUEUE_SIZE.fetch_add(1, Ordering::Relaxed);
564	                    }
565	
566	                    // Wait for token from queue processor
567	                    match permit_rx.await {
568	                        Ok(Ok(())) => {
569	                            debug!("Acquired token from queue");
570	                            Metrics::record_http_rate_limit(metrics_labels::RATE_LIMIT_ALLOWED);
571	                            // Dequeue for embeddings
572	                            if is_embeddings {
573	                                EMBEDDINGS_QUEUE_SIZE.fetch_sub(1, Ordering::Relaxed);
574	                            }
575	
576	                            let response = next.run(request).await;
577	
578	                            // Wrap the response body with TokenGuardBody to return token when stream ends
579	                            let (parts, body) = response.into_parts();
580	                            let guarded_body = TokenGuardBody::new(body, token_bucket, 1.0);
581	                            Response::from_parts(parts, Body::new(guarded_body))
582	                        }
583	                        Ok(Err(status)) => {
584	                            warn!("Queue returned error status: {}", status);
585	                            Metrics::record_http_rate_limit(metrics_labels::RATE_LIMIT_REJECTED);
586	                            // Dequeue for embeddings on error
587	                            if is_embeddings {
588	                                EMBEDDINGS_QUEUE_SIZE.fetch_sub(1, Ordering::Relaxed);
589	                            }
590	                            status.into_response()
591	                        }
592	                        Err(_) => {
593	                            error!("Queue response channel closed");
594	                            Metrics::record_http_rate_limit(metrics_labels::RATE_LIMIT_REJECTED);
595	                            // Dequeue for embeddings on channel error
596	                            if is_embeddings {
597	                                EMBEDDINGS_QUEUE_SIZE.fetch_sub(1, Ordering::Relaxed);
598	                            }
599	                            StatusCode::INTERNAL_SERVER_ERROR.into_response()
600	                        }
601	                    }
602	                }
603	                Err(_) => {
604	                    warn!("Request queue is full, returning 429");
605	                    Metrics::record_http_rate_limit(metrics_labels::RATE_LIMIT_REJECTED);
606	                    StatusCode::TOO_MANY_REQUESTS.into_response()
607	                }
608	            }
609	        } else {
610	            warn!("No tokens available and queuing is disabled, returning 429");
611	            Metrics::record_http_rate_limit(metrics_labels::RATE_LIMIT_REJECTED);
612	            StatusCode::TOO_MANY_REQUESTS.into_response()
613	        }
614	    }
615	}
