647	/// Tower Service for HTTP metrics collection
648	#[derive(Clone)]
649	pub struct HttpMetricsMiddleware<S> {
650	    inner: S,
651	    in_flight_request_tracker: Arc<InFlightRequestTracker>,
652	}
653	
654	impl<S> Service<Request> for HttpMetricsMiddleware<S>
655	where
656	    S: Service<Request, Response = Response> + Send + Clone + 'static,
657	    S::Future: Send + 'static,
658	{
659	    type Response = S::Response;
660	    type Error = S::Error;
661	    type Future =
662	        Pin<Box<dyn std::future::Future<Output = Result<Self::Response, Self::Error>> + Send>>;
663	
664	    fn poll_ready(&mut self, cx: &mut Context<'_>) -> Poll<Result<(), Self::Error>> {
665	        self.inner.poll_ready(cx)
666	    }
667	
668	    fn call(&mut self, req: Request) -> Self::Future {
669	        // Convert method to static string to avoid allocation
670	        let method = method_to_static_str(req.method().as_str());
671	        let path = normalize_path_for_metrics(req.uri().path());
672	        let start = Instant::now();
673	
674	        let mut inner = self.inner.clone();
675	        let in_flight_request_tracker = self.in_flight_request_tracker.clone();
676	
677	        Box::pin(async move {
678	            // Increment inside async block - ensures no leak if future is dropped before polling
679	            let active = ACTIVE_HTTP_CONNECTIONS.fetch_add(1, Ordering::Relaxed) + 1;
680	            Metrics::set_http_connections_active(active as usize);
681	
682	            let guard = in_flight_request_tracker.track();
683	
684	            // Capture result before decrementing to ensure decrement happens on error too
685	            let result = inner.call(req).await;
686	
687	            drop(guard);
688	
689	            // Always decrement, regardless of success or failure
690	            let active = ACTIVE_HTTP_CONNECTIONS.fetch_sub(1, Ordering::Relaxed) - 1;
691	            Metrics::set_http_connections_active(active as usize);
692	
693	            let response = result?;
694	
695	            let duration = start.elapsed();
696	            Metrics::record_http_duration(method, &path, duration);
697	
698	            Ok(response)
699	        })
700	    }
701	}
