703	/// Normalize path for metrics to avoid high cardinality.
704	/// Replaces dynamic segments (IDs, UUIDs) with `{id}` placeholder.
705	/// Only allocates when normalization is needed; uses single-pass with byte offsets.
706	fn normalize_path_for_metrics(path: &str) -> String {
707	    let bytes = path.as_bytes();
708	    let mut segment_start = 0;
709	    let mut segment_idx = 0;
710	    let mut result: Option<String> = None;
711	
712	    for (pos, &b) in bytes.iter().enumerate() {
713	        if b == b'/' || pos == bytes.len() - 1 {
714	            // Determine segment end (include last char if not a slash)
715	            let segment_end = if b == b'/' { pos } else { pos + 1 };
716	            let segment = &path[segment_start..segment_end];
717	
718	            // Check segments after index 2 for dynamic IDs
719	            if segment_idx > 2 && !segment.is_empty() && is_dynamic_id(segment) {
720	                // Initialize result with everything before this segment
721	                let result = result.get_or_insert_with(|| {
722	                    let mut s = String::with_capacity(path.len());
723	                    s.push_str(&path[..segment_start]);
724	                    s
725	                });
726	                result.push_str("{id}");
727	            } else if let Some(ref mut r) = result {
728	                // Already normalizing, append this segment as-is
729	                r.push_str(segment);
730	            }
731	
732	            // Add slash after segment (except at end)
733	            if b == b'/' {
734	                if let Some(ref mut r) = result {
735	                    r.push('/');
736	                }
737	                segment_start = pos + 1;
738	                segment_idx += 1;
739	            }
740	        }
741	    }
742	
743	    result.unwrap_or_else(|| path.to_owned())
744	}
745	
746	/// Check if segment looks like a dynamic ID (prefixed ID, UUID, or numeric).
747	#[inline]
748	fn is_dynamic_id(s: &str) -> bool {
749	    // Prefixed IDs: resp_xxx, chatcmpl_xxx (len > 10 with underscore)
750	    if s.len() > 10 && s.contains('_') {
751	        return true;
752	    }
753	    // UUIDs: 32+ hex chars with dashes
754	    if s.len() >= 32 && s.bytes().all(|b| b.is_ascii_hexdigit() || b == b'-') {
755	        return true;
756	    }
757	    // Numeric IDs
758	    !s.is_empty() && s.bytes().all(|b| b.is_ascii_digit())
759	}
