761	pub async fn wasm_middleware(
762	    State(app_state): State<Arc<AppState>>,
763	    request: Request<Body>,
764	    next: Next,
765	) -> Result<Response, StatusCode> {
766	    // Check if WASM is enabled
767	    if !app_state.context.router_config.enable_wasm {
768	        return Ok(next.run(request).await);
769	    }
770	
771	    // Get WASM manager
772	    let wasm_manager = match &app_state.context.wasm_manager {
773	        Some(manager) => manager,
774	        None => {
775	            return Ok(next.run(request).await);
776	        }
777	    };
778	
779	    // Get request ID from extensions or generate one
780	    let request_id = request
781	        .extensions()
782	        .get::<RequestId>()
783	        .map(|r| r.0.clone())
784	        .unwrap_or_else(|| generate_request_id(request.uri().path()));
785	
786	    // ===== OnRequest Phase =====
787	    let on_request_attach_point =
788	        WasmModuleAttachPoint::Middleware(MiddlewareAttachPoint::OnRequest);
789	
790	    let modules_on_request =
791	        match wasm_manager.get_modules_by_attach_point(on_request_attach_point.clone()) {
792	            Ok(modules) => modules,
793	            Err(e) => {
794	                error!("Failed to get WASM modules for OnRequest: {}", e);
795	                return Ok(next.run(request).await);
796	            }
797	        };
798	
799	    let response = if modules_on_request.is_empty() {
800	        next.run(request).await
801	    } else {
802	        // Extract request body once before processing modules
803	        let method = request.method().clone();
804	        let uri = request.uri().clone();
805	        let mut headers = request.headers().clone();
806	        let max_body_size = wasm_manager.get_max_body_size();
807	        let body_bytes = match axum::body::to_bytes(request.into_body(), max_body_size).await {
808	            Ok(bytes) => bytes.to_vec(),
809	            Err(e) => {
810	                error!("Failed to read request body: {}", e);
811	                // Create a minimal request with empty body for error recovery
812	                let error_request = Request::builder()
813	                    .uri(uri)
814	                    .body(Body::empty())
815	                    .unwrap_or_else(|_| Request::new(Body::empty()));
816	                return Ok(next.run(error_request).await);
817	            }
818	        };
819	
820	        // Process each OnRequest module
821	        let mut modified_body = body_bytes;
822	
823	        // Pre-compute strings once before the loop to avoid repeated allocations
824	        let method_str = method.to_string();
825	        let path_str = uri.path().to_string();
826	        let query_str = uri.query().unwrap_or("").to_string();
827	
828	        for module in modules_on_request {
829	            // Build WebAssembly request from collected data
830	            let wasm_headers = build_wasm_headers_from_axum_headers(&headers);
831	            let wasm_request = WasmRequest {
832	                method: method_str.clone(),
833	                path: path_str.clone(),
834	                query: query_str.clone(),
835	                headers: wasm_headers,
836	                body: modified_body.clone(),
837	                request_id: request_id.clone(),
838	                now_epoch_ms: std::time::SystemTime::now()
839	                    .duration_since(std::time::UNIX_EPOCH)
840	                    .unwrap_or_else(|_| Duration::from_millis(0))
841	                    .as_millis() as u64,
842	            };
843	
844	            // Execute WASM component
845	            let action = match wasm_manager
846	                .execute_module_for_attach_point(
847	                    &module,
848	                    on_request_attach_point.clone(),
849	                    WasmComponentInput::MiddlewareRequest(wasm_request),
850	                )
851	                .await
852	            {
853	                Some(action) => action,
854	                None => continue, // Continue to next module on error
855	            };
856	
857	            // Process action
858	            match action {
859	                Action::Continue => {}
860	                Action::Reject(status) => {
861	                    return Err(StatusCode::from_u16(status).unwrap_or(StatusCode::BAD_REQUEST));
862	                }
863	                Action::Modify(modify) => {
864	                    // Apply modifications to headers and body
865	                    apply_modify_action_to_headers(&mut headers, &modify);
866	                    if let Some(body_bytes) = modify.body_replace {
867	                        modified_body = body_bytes;
868	                    }
869	                }
870	            }
871	        }
872	
873	        // Reconstruct request with modifications
874	        let mut final_request = Request::builder()
875	            .method(method)
876	            .uri(uri)
877	            .body(Body::from(modified_body))
878	            .unwrap_or_else(|_| Request::new(Body::empty()));
879	        *final_request.headers_mut() = headers;
880	
881	        // Continue with request processing
882	        next.run(final_request).await
883	    };
884	
885	    // ===== OnResponse Phase =====
886	    let on_response_attach_point =
887	        WasmModuleAttachPoint::Middleware(MiddlewareAttachPoint::OnResponse);
888	
889	    let modules_on_response =
890	        match wasm_manager.get_modules_by_attach_point(on_response_attach_point.clone()) {
891	            Ok(modules) => modules,
892	            Err(e) => {
893	                error!("Failed to get WASM modules for OnResponse: {}", e);
894	                return Ok(response);
895	            }
896	        };
897	    if modules_on_response.is_empty() {
898	        return Ok(response);
899	    }
900	    // Extract response data once before processing modules
901	    let mut status = response.status();
902	    let mut headers = response.headers().clone();
903	    let max_body_size = wasm_manager.get_max_body_size();
904	    let mut body_bytes = match axum::body::to_bytes(response.into_body(), max_body_size).await {
905	        Ok(bytes) => bytes.to_vec(),
906	        Err(e) => {
907	            error!("Failed to read response body: {}", e);
908	            // Create a minimal response with empty body for error recovery
909	            let error_response = Response::builder()
910	                .status(status)
911	                .body(Body::empty())
912	                .unwrap_or_else(|_| Response::new(Body::empty()));
913	            return Ok(error_response);
914	        }
915	    };
916	
917	    // Process each OnResponse module
918	    for module in modules_on_response {
919	        // Build WebAssembly response from collected data
920	        let wasm_headers = build_wasm_headers_from_axum_headers(&headers);
921	        let wasm_response = WasmResponse {
922	            status: status.as_u16(),
923	            headers: wasm_headers,
924	            body: body_bytes.clone(),
925	        };
926	
927	        // Execute WASM component
928	        let action = match wasm_manager
929	            .execute_module_for_attach_point(
930	                &module,
931	                on_response_attach_point.clone(),
932	                WasmComponentInput::MiddlewareResponse(wasm_response),
933	            )
934	            .await
935	        {
936	            Some(action) => action,
937	            None => continue, // Continue to next module on error
938	        };
939	
940	        // Process action - apply modifications incrementally
941	        match action {
942	            Action::Continue => {
943	                // Continue to next module
944	            }
945	            Action::Reject(status_code) => {
946	                // Override response status
947	                status = StatusCode::from_u16(status_code).unwrap_or(StatusCode::BAD_REQUEST);
948	                // Return immediately with current state
949	                let final_response = Response::builder()
950	                    .status(status)
951	                    .body(Body::from(body_bytes))
952	                    .unwrap_or_else(|_| Response::new(Body::empty()));
953	                let mut final_response = final_response;
954	                *final_response.headers_mut() = headers;
955	                return Ok(final_response);
956	            }
957	            Action::Modify(modify) => {
958	                // Apply status modification
959	                if let Some(new_status) = modify.status {
960	                    status = StatusCode::from_u16(new_status).unwrap_or(status);
961	                }
962	                // Apply headers modifications
963	                apply_modify_action_to_headers(&mut headers, &modify);
964	                // Apply body_replace
